import java.util.*;

public static long solve(long[] nums, long k) {
    int n = nums.length;
    long[] prefixSum = new long[n + 1];
    for (int i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    Map<Long, Integer> modCount = new HashMap<>();
    modCount.put(0L, 1); // Base case: sum 0 mod k is 0, occurs once

    long minSum = Long.MAX_VALUE;

    for (int i = 1; i <= n; i++) {
        long currentSum = prefixSum[i];
        long mod = currentSum % k;
        if (mod < 0) mod += k; // Ensure mod is non-negative

        // Check if there's a previous prefix sum with the same mod
        if (modCount.containsKey(mod)) {
            int prevIndex = modCount.get(mod);
            // The subarray from prevIndex+1 to i has sum divisible by k
            long subarraySum = currentSum - prefixSum[prevIndex];
            minSum = Math.min(minSum, subarraySum);
        }

        // Update the count of this mod
        modCount.put(mod, i);
    }

    // The minimum sum is the minimum between the original sum and the minimum subarray sum found
    long totalSum = prefixSum[n];
    return Math.min(totalSum, minSum);
}
