public static long solve(long[] nums, long k) {
    long totalSum = 0;
    for (long num : nums) {
        totalSum += num;
    }

    Map<Long, Integer> modCount = new HashMap<>();
    long prefixSum = 0;
    modCount.put(0L, 1); // To handle cases where a prefix sum is divisible by k

    for (long num : nums) {
        prefixSum += num;
        long mod = prefixSum % k;
        if (mod < 0) mod += k; // Ensure mod is non-negative
        modCount.put(mod, modCount.getOrDefault(mod, 0) + 1);
    }

    long minSum = totalSum;
    for (Map.Entry<Long, Integer> entry : modCount.entrySet()) {
        long mod = entry.getKey();
        int count = entry.getValue();
        if (count > 0) {
            long possibleSum = (count * k) - (mod * count);
            minSum = Math.min(minSum, possibleSum);
        }
    }

    return minSum;
}
